const configureAwilix = async (fastify: FastifyInstance) => {
    const container = createContainer({
        injectionMode: InjectionMode.CLASSIC,
        strict: true,
    });

    fastify.decorate("di", container);

    // Register dependencies from plugins and libraries
    fastify.di.register({
        log: asValue(fastify.log),
        prisma: asValue(fastify.prisma),
        config: asValue(fastify.config),
    });

    // Register dependencies from the application: repositories, services, route handlers
    await container.loadModules(
        [
            path.join(__dirname, "../modules/**/*.{service,handler}.{js,ts}"),
            path.join(
                __dirname,
                "../database/repositories/{*,**/*}.repository.{js,ts}"
            ),
        ],
        {
            resolverOptions: {
                register: resolverOptionsRegister(container),
            },
            esModules: true,
        }
    );
};

export default fp(configureAwilix, {
    name: FastifyPlugin.Awilix,
    dependencies: [FastifyPlugin.Prisma, FastifyPlugin.Env],
});

import {
  FastifyPluginAsyncTypebox,
  Type
} from '@fastify/type-provider-typebox'
import { CredentialsSchema } from '../../../schemas/auth.js'

const plugin: FastifyPluginAsyncTypebox = async (fastify) => {
  const { usersRepository, passwordManager } = fastify
  fastify.post(
    '/login',
    {
      schema: {
        body: CredentialsSchema,
        response: {
          200: Type.Object({
            success: Type.Boolean(),
            message: Type.Optional(Type.String())
          }),
          401: Type.Object({
            message: Type.String()
          })
        },
        tags: ['Authentication']
      }
    },
    async function (request, reply) {
      const { email, password } = request.body

      return fastify.knex.transaction(async (trx) => {
        const user = await usersRepository.findByEmail(email, trx)

        if (user) {
          const isPasswordValid = await passwordManager.compare(
            password,
            user.password
          )
          if (isPasswordValid) {
            const roles = await usersRepository.findUserRolesByEmail(email, trx)

            request.session.user = {
              id: user.id,
              email: user.email,
              username: user.username,
              roles: roles.map((role) => role.name)
            }

            await request.session.save()

            return { success: true }
          }
        }

        reply.status(401)

        return { message: 'Invalid email or password.' }
      })
    }
  )
}

export default plugin

import { listProductsSchema, deleteProductSchema } from './schema';

export default function productHandler(server, options, next) {
	server.get(
		'/',
		{ schema: listProductsSchema },
		async (req, res) => {
			req.log.info('list products from db');
			const products = await server.db.products.find();
			res.send(products);
		}
	);

	server.get('/:_id', async (req, res) => {
		req.log.info('get one products from db');
		const product = await server.db.products.findOne(req.params._id);
		res.send(product);
	});

	server.post('/', async (req, res) => {
		req.log.info('Add products to db');
		const products = await server.db.products.save(req.body);
		res.status(201).send(products);
	});

	server.put('/:_id', async (req, res) => {
		req.log.info('Update product to db');
		const _id = req.params._id;
		const products = await server.db.products.save({ _id, ...req.body });
		res.status(200).send(products);
	});

	server.delete(
		'/:_id',
		{ schema: deleteProductSchema },
		async (req, res) => {
			req.log.info(`delete product ${req.params._id} from db`);
			const product = await server.db.products.findOne(req.params._id);
			await server.db.products.remove(product);
			res.code(200).send({});
		}
	);

	next();
}

