import { FastifyReply, FastifyRequest } from 'fastify';
import { Controller, ErrorHandler, GET, Scope } from 'fastify-decorators';
import { ErrorType } from './error-type.js';

@Controller({
  route: '/stateful/error-handling',
  scope: Scope.SINGLETON,
})
export default class StatelessController {
  @GET({
    url: '/',
    options: { schema: { querystring: { type: 'object', properties: { errorType: { type: 'number' } } } } },
  })
  async getStateful(request: FastifyRequest<{ Querystring: { errorType: ErrorType } }>): Promise<never> {
    switch (request.query.errorType) {
      case ErrorType.GENERIC:
        throw new Error('Generic error happened');
      case ErrorType.CUSTOM:
        throw { code: 'CUSTOM_ERROR_CODE' };
      case ErrorType.SYNTAX:
        throw new SyntaxError('Syntax error happened');
      case ErrorType.TYPE:
        throw new TypeError('Type error happened');
    }
  }

  @ErrorHandler('CUSTOM_ERROR_CODE')
  customErrorHandler(error: Error, request: FastifyRequest, reply: FastifyReply): void {
    reply.status(503).send(error.message);
  }

  @ErrorHandler(TypeError)
  typeErrorHandler(error: TypeError, request: FastifyRequest, reply: FastifyReply): void {
    reply.status(502).send(error.message);
  }

  @ErrorHandler(SyntaxError)
  syntaxErrorHandler(error: SyntaxError, request: FastifyRequest, reply: FastifyReply): void {
    reply.status(501).send(error.message);
  }

  @ErrorHandler()
  genericErrorHandler(error: Error, request: FastifyRequest, reply: FastifyReply): void {
    reply.status(500).send(error.message);
  }
}

import { FastifyReply, FastifyRequest } from 'fastify';
import { Controller, DELETE, ErrorHandler, GET, POST } from 'fastify-decorators';
import { schema, users } from './user.js';
import { UserError } from './user-error.js';

@Controller('/user')
export default class UserController {
  @GET('/:username', { schema })
  public getUser(request: FastifyRequest<{ Params: { username: string } }>, reply: FastifyReply): void {
    const { username } = request.params;
    if (!users.has(username)) throw new UserError('USER_NOT_FOUND');

    reply.send({ username });
  }

  @DELETE('/:username')
  public deleteUser(request: FastifyRequest<{ Params: { username: string } }>, reply: FastifyReply): void {
    const { username } = request.params;
    if (!users.has(username)) throw new UserError('USER_NOT_FOUND');

    users.delete(username);
    reply.status(204).send();
  }

  @POST('/', { schema })
  public createUser(request: FastifyRequest<{ Body: { username: string } }>, reply: FastifyReply): void {
    const { username } = request.body;
    if (users.has(username)) throw new UserError('USER_ALREADY_EXISTS');

    reply.status(200).send({ username });
  }

  @ErrorHandler('USER_ALREADY_EXISTS')
  userExists(error: Error, request: FastifyRequest, reply: FastifyReply): void {
    reply.status(422).send({ message: 'User already exists' });
  }

  @ErrorHandler('USER_NOT_FOUND')
  public notExists(error: Error, request: FastifyRequest, reply: FastifyReply): void {
    reply.status(404).send({ message: 'User not found' });
  }
}

'use strict'

const fastifySession = require('@fastify/session')
const fastifyCookie = require('@fastify/cookie')
const fastifyFormbody = require('@fastify/formbody')

const { loginPage, defaultPage } = require('./html')

function plugin (instance, options, next) {
  // register the required plugins
  instance.register(fastifyFormbody)
  instance.register(fastifyCookie)
  instance.register(fastifySession, {
    cookieName: 'sessionId',
    secret: 'a secret with minimum length of 32 characters',
    cookie: { maxAge: 1800000, secure: false }
  })

  // add a login route that returns a login page
  instance.get('/login', (request, reply) => {
    reply.type('text/html')
    reply.send(loginPage())
  })

  // add a login route that handles the actual login
  instance.post('/login', (request, reply) => {
    const { email, password } = request.body

    if (password === 'abcdef') {
      request.session.authenticated = true
      reply.type('text/html')
      reply.send(defaultPage(true))
    } else {
      reply.redirect('/login', 401)
    }
  });

  instance.get('/', (request, reply) => {
    reply.type('text/html')
    reply.send(defaultPage(request.session.authenticated))
  });

  // add a logout route
  instance.get('/logout', (request, reply) => {
    if (request.session.authenticated) {
      request.session.destroy((err) => {
        if (err) {
          reply.status(500)
          reply.send('Internal Server Error')
        } else {
          reply.redirect('/')
        }
      })
    } else {
      reply.redirect('/')
    }
  });

  next()
}

module.exports = plugin

#! /usr/bin/env node

'use strict'

const parseArgs = require('./args')
const { loadEnvQuitely } = require('./env-loader')
const log = require('./log')
const {
  exit,
  requireFastifyForModule,
  requireServerPluginFromPath,
  showHelpForCommand
} = require('./util')

let Fastify = null

function loadModules (opts) {
  try {
    Fastify = requireFastifyForModule(opts._[0]).module
  } catch (e) {
    module.exports.stop(e)
  }
}

function printPlugins (args) {
  const opts = parseArgs(args)
  if (opts.help) {
    return showHelpForCommand('print-plugins')
  }

  if (opts._.length !== 1) {
    console.error('Missing the required file parameter\n')
    return showHelpForCommand('print-plugins')
  }

  loadModules(opts)

  return runFastify(opts)
}

async function runFastify (opts) {
  loadEnvQuitely()

  let file = null

  try {
    file = await requireServerPluginFromPath(opts._[0])
  } catch (e) {
    return module.exports.stop(e)
  }

  const fastify = Fastify(opts.options)

  const pluginOptions = {}
  if (opts.prefix) {
    pluginOptions.prefix = opts.prefix
  }

  await fastify.register(file, pluginOptions)
  await fastify.ready()
  log('debug', fastify.printPlugins())

  return fastify
}

function stop (message) {
  exit(message)
}

function cli (args) {
  return printPlugins(args).then(fastify => {
    if (fastify) return fastify.close()
  })
}

module.exports = { cli, stop, printPlugins }

if (require.main === module) {
  cli(process.argv.slice(2))
}

