'use strict'

function execRedis (redisClient, method, args) {
  return new Promise(function (resolve, reject) {
    args.push(function (err, result) {
      if (err) return reject(err)
      resolve(result)
    })
    redisClient[method].apply(redisClient, args)
  })
}

function follow (redisClient, meId, otherId) {
  return Promise.all([
    execRedis(redisClient, 'zadd', [`following:${meId}`, Date.now(), otherId]),
    execRedis(redisClient, 'zadd', [`followers:${otherId}`, Date.now(), meId])
  ])
}

function unfollow (redisClient, meId, otherId) {
  return Promise.all([
    execRedis(redisClient, 'zrem', [`following:${meId}`, otherId]),
    execRedis(redisClient, 'zrem', [`followers:${otherId}`, meId])
  ])
}

function getFollowing (redisClient, meId) {
  return execRedis(redisClient, 'zrange', [`following:${meId}`, 0, -1])
}

function getFollowers (redisClient, otherId) {
  return execRedis(redisClient, 'zrange', [`followers:${otherId}`, 0, -1])
}

class FollowService {
  constructor (redisClient) {
    this.redisClient = redisClient
  }

  follow (meId, otherId) {
    return follow(this.redisClient, meId + '', otherId + '')
  }

  unfollow (meId, otherId) {
    return unfollow(this.redisClient, meId + '', otherId + '')
  }

  getFollowing (meId) {
    return getFollowing(this.redisClient, meId + '')
  }

  getFollowers (otherId) {
    return getFollowers(this.redisClient, otherId + '')
  }
}

module.exports = FollowService

'use strict'

const DUPLICATE_KEY_ERROR_CODE = 11000

const errors = require('../errors')

class UserService {
  constructor (userCollection) {
    this.userCollection = userCollection
  }

  async register (username, password) {
    let writeResult
    try {
      writeResult = await this.userCollection.insertOne({ username, password })
    } catch (e) {
      if (e.code === DUPLICATE_KEY_ERROR_CODE) {
        throw new Error(errors.USERNAME_IS_NOT_AVAILABLE)
      }
      throw e
    }

    return writeResult.insertedId
  }

  async login (username, password) {
    const users = await this.userCollection.find({ username, password }, { projection: {password: 0} }).toArray()
    const user = users[0]

    if (!user) throw new Error(errors.WRONG_CREDENTIAL)

    return user
  }

  getProfile (_id) {
    return this.userCollection.findOne({ _id }, { projection: {password: 0} })
  }

  async search (searchString) {
    const query = {
      username: { $regex: searchString }
    }
    const users = await this.userCollection.find(query, { projection: {password: 0} }).limit(5).toArray()
    return users
  }

  async ensureIndexes (db) {
    await db.command({
      'collMod': this.userCollection.collectionName,
      validator: {
        username: { $type: 'string' },
        password: { $type: 'string' }
      }
    })
    await this.userCollection.createIndex({ username: 1 }, { unique: true })
  }
}

module.exports = UserService

